mapper.select:
select

from knowledge_directory
where deleted = 0

    and knowledge_base_id = #{query.knowledgeBaseId}


    and description like concat('%', #{query.description}, '%')


    and status = #{query.status}


    and create_time >= #{query.createStartTime}


    and create_time <= #{query.createEndTime}

order by level asc, sort_order asc, id asc

select count(1)
from knowledge_directory
where deleted = 0
  and knowledge_base_id = #{knowledgeBaseId}
  and path = #{path}

    and id != #{excludeId}
